  vector<int> prefix(n + 1);
  for(int i = 1; i <= n; i++) {
    prefix[i] = prefix[i - 1] + A[i];
  }
  int minSum = INT_MAX;
  for(int i = 1; i <= n; i++) {
    for(int j = i; j <= n; j++) {
      int sum = prefix[j] - prefix[i - 1];
