class Solution {
public:
int solve(vector<int>& A, int k) {
  int n = A.size();
  vector<int> prefix(n + 1);
  for(int i = 1; i <= n; i++) {
    prefix[i] = prefix[i - 1] + A[i - 1];
  }
  int minSum = INT_MAX;
  for(int i = 1; i <= n; i++) {
    for(int j = i; j <= n; j++) {
      int sum = prefix[j] - prefix[i - 1];
      if(k > 0) {
        minSum = min(minSum, sum);
        k--;
      }
    }
  }
  return minSum;
}


int main() {
  int n, k;
  cin >> n >> k;
  int A[n];
  for(int i = 0; i < n; i++) cin >> A[i];
  cout << solve(A, k) << endl;
  return 0;
}
